import type { IConformance } from '@/enums/PDFAConformance'
import type { TemplateDataToPopulateDocument } from '@/models/TemplateDataToPopulateDocument'
import type { FetchedCustomFont, FetchedNodeCustomFont, MessageId } from '@pspdfkit/core'
import type { IDocumentOfficeFormat } from '@/enums/OfficeDocumentFormat'

export enum Conformance {
  'pdf_a_1a',
  'pdf_a_1b',
  'pdf_a_2a',
  'pdf_a_2u',
  'pdf_a_2b',
  'pdf_a_3a',
  'pdf_a_3u',
  'pdf_a_3b',
  'pdf_a_4',
  'pdf_a_4e',
  'pdf_a_4f',
}

export interface GdPictureInterface {
  toPdf(document: ArrayBuffer, conformance?: IConformance): Promise<ArrayBuffer>
  toOffice(document: ArrayBuffer, format: IDocumentOfficeFormat): Promise<ArrayBuffer>
  destroy(): void
}

export interface GdPictureSpawner {
  setMessageHandler: (fn: (event: MessageEvent) => void) => void
  postMessage(message: any, options?: StructuredSerializeOptions | undefined): void | undefined
  postMessage(message: any, transferList?: Transferable[]): void
  terminate: () => void
}

export interface GdPictureCommands {
  loadModule(
    baseUrl: string,
    aot: boolean,
    origin: string,
    licenseKey: string | undefined | null,
    customFonts: FetchedCustomFont[] | FetchedNodeCustomFont[] | undefined | null,
    dynamicFonts?: string | null,
  ): Promise<void>
  toOffice(document: ArrayBuffer, format: IDocumentOfficeFormat): Promise<ArrayBuffer>
  toPdf(document: ArrayBuffer, conformance?: Conformance): Promise<ArrayBuffer>
  populateDocumentTemplate(
    document: ArrayBuffer,
    data: TemplateDataToPopulateDocument,
  ): Promise<ArrayBuffer>
}

export type Request<K extends keyof GdPictureCommands> = {
  id: MessageId
  action: K
  args: Parameters<GdPictureCommands[K]>
}

export type Response<K extends keyof GdPictureCommands> =
  | {
      id: MessageId
      error: string
      callArgs?: Parameters<GdPictureCommands[K]>
    }
  | {
      id: MessageId
      result: ReturnType<GdPictureCommands[K]>
      responseTransferList?: Array<ArrayBuffer>
    }
