import { invariant } from '@pspdfkit/shared'

import type { GdPictureSpawner } from '../GdPictureTypes'

async function getSpawner(inline = true): Promise<GdPictureSpawner> {
  let worker: Worker | null

  if (inline) {
    const { default: GdPictureWorker } = await import(
      /* webpackChunkName: 'gdpicture-worker' */
      // eslint-disable-next-line @typescript-eslint/ban-ts-comment
      /* @ts-ignore */
      'worker-loader?inline=no-fallback!../workers/GdPictureBrowser.worker.ts'
    )

    worker = new GdPictureWorker() as Worker
  } else {
    worker = new Worker(
      /* webpackChunkName: 'pspdfkit-lib/gdpicture-worker' */
      /* @ts-expect-error */
      new URL('../workers/GdPictureBrowser.worker.ts', import.meta.url),
    )
  }

  return {
    setMessageHandler(fn: (event: MessageEvent) => void) {
      invariant(worker, 'Worker is null')

      worker.onmessage = fn
    },
    postMessage(message, transferList) {
      worker?.postMessage(message, transferList)
    },

    terminate() {
      worker?.terminate()
      worker = null
    },
  }
}

export default getSpawner
