import { invariant, log } from '@pspdfkit/shared'
import { downloadAndParseDynamicFontsFile } from '@pspdfkit/core/src/utils'

import { loadGdPicture } from './Loader'
import { Conformance } from './GdPictureTypes'

import type { FontSubstitution } from '@/models/FontSubstitution'
import type { GdPictureCommands as GdPictureInterface } from './GdPictureTypes'
import type { execJsonTypeMap } from '@/typings/GdPictureWasmCommands'
import type { FetchedCustomFont, FetchedNodeCustomFont } from '@pspdfkit/core'
import type { TemplateDataToPopulateDocument } from '@/models/TemplateDataToPopulateDocument'
import type { IDocumentOfficeFormat } from '@/enums/OfficeDocumentFormat'

// path to the current working document of the instance
const CREATE_FILE_PATH = '/create.pdf'
// path where exported and temporary changes are written
// and read from, i.e. when exporting it or calling `exportPDFWithOperations`
const SAVE_FILE_PATH = '/save.pdf'

// path to the current working docx template file of the instance
const CREATE_DOCX_PATH = '/create.docx'
// path where exported and temporary changes are written of the docx template
const SAVE_DOCX_PATH = '/save.docx'

const TEMPLATE_DATA_JSON_PATH = '/templateData.json'

const ERROR_MODULE_NOT_LOADED = 'WebAssembly module not loaded.'

// Set this when you need to debug the requests and responses in the Web <-> GdPicture communication.
const ENABLE_GDPICTURE_LOG = false

// @ts-expect-error
const isWorker = typeof WorkerGlobalScope !== 'undefined' && self instanceof WorkerGlobalScope

let module: any = null
let api: any = null

function execJsonCommand<K extends keyof execJsonTypeMap>(
  command: K,
  ...args: execJsonTypeMap[K]['args']
): execJsonTypeMap[K]['return'] {
  invariant(api, 'GdPicture WebAssembly is not loaded.')

  let start

  if (ENABLE_GDPICTURE_LOG) {
    start = performance.now()
    log(`Request: ${command}(${args.map(arg => JSON.stringify(arg)).join(', ')})`)
  }

  let options

  for (const arg of args) {
    options = Object.assign(args[0], arg)
  }

  const jsonCommand = JSON.stringify({
    type: command,
    ...options,
  })

  const result = JSON.parse(api.CommandHandler(jsonCommand))

  if (ENABLE_GDPICTURE_LOG) {
    invariant(typeof start === 'number')
    log(
      `Response from ${command} (${(performance.now() - start).toFixed(2)} ms): ${JSON.stringify(
        result,
      )}`,
    )
  }

  if (!result.success) {
    throw new Error(result.errorReason + ': ' + result.errorMessage + '\n' + result.error)
  }

  return result
}

export default class GdPictureWorker implements GdPictureInterface {
  _mountCustomFonts(
    customFonts: Array<FetchedCustomFont> | Array<FetchedNodeCustomFont>,
    customFontsPath: string,
  ) {
    invariant(module, ERROR_MODULE_NOT_LOADED)
    module.FS.mkdir(customFontsPath)

    // Font loading in Node.js
    if (process.env.BACKEND_BUILD === 'true') {
      customFonts.forEach(customFont => {
        module.FS.writeFile(
          `${customFontsPath}/${customFont.name}`,
          new Uint8Array(customFont.data as ArrayBufferLike),
        )
      })
    } else {
      const fileSystem = isWorker ? module.FS.filesystems.WORKERFS : module.FS.filesystems.MEMFS
      module.FS.mount(
        fileSystem,
        {
          blobs: customFonts,
        },
        customFontsPath,
      )
    }
  }

  async loadModule(
    baseCoreUrlOrWasmPath: string | { wasmLoaderPath: string; baseUrl: string },
    aot: boolean,
    origin: string,
    licenseKey: string | undefined | null,
    customFonts?: Array<FetchedCustomFont> | Array<FetchedNodeCustomFont> | null | undefined,
    dynamicFonts?: string | null,
    fontSubstitutions?: FontSubstitution[] | null,
  ) {
    let start

    if (ENABLE_GDPICTURE_LOG) {
      start = performance.now()
      log('loading GdPicture WASM')
    }

    const { Assemblies, Module } = await loadGdPicture(baseCoreUrlOrWasmPath, aot)

    api = Assemblies.GdPictureWasm.API
    module = Module

    if (ENABLE_GDPICTURE_LOG) {
      invariant(typeof start === 'number')
      log(`Finished Loading GdPicture WASM (${(performance.now() - start).toFixed(2)} ms)`)
    }

    execJsonCommand(
      'gdpicture/setLicense',
      {
        origin: origin,
      },
      { licenseKey: !licenseKey ? 'DEMO_PSPDFKIT_WEB' : licenseKey },
    )

    const customFontsPath = customFonts ? '/fonts' : ''

    if (customFonts && !module.FS.analyzePath(customFontsPath).exists) {
      this._mountCustomFonts(customFonts, customFontsPath)

      execJsonCommand('gdpicture/setFonts', {
        fontPaths: [customFontsPath],
      })
    }

    if (dynamicFonts) {
      const dynamicFontsJSON = await downloadAndParseDynamicFontsFile(dynamicFonts)
      const dynamicFontsBaseURL = dynamicFonts.split('/').slice(0, -1).join('/')

      execJsonCommand('gdpicture/setDynamicFontLoading', {
        baseUrl: dynamicFontsBaseURL,
        allowedFonts: dynamicFontsJSON.availableFonts,
        v: 1,
      })
    }

    if (fontSubstitutions) {
      execJsonCommand('gdpicture/setFontSubstitutions', {
        fontSubstitutions: fontSubstitutions,
      })
    }
  }

  toPdf(fileBuffer: ArrayBuffer, conformance?: Conformance): Promise<ArrayBuffer> {
    module.FS.writeFile(CREATE_FILE_PATH, new Uint8Array(fileBuffer))

    const output = {
      file: SAVE_FILE_PATH,
      format: 'pdf' as const,
    }

    if (conformance && conformance in Conformance) {
      output['conformance'] = conformance
    }

    try {
      execJsonCommand('gdpicture/process', {
        input: {
          file: CREATE_FILE_PATH,
        },
        output,
      })

      return module.FS.readFile(SAVE_FILE_PATH).buffer
    } finally {
      try {
        module.FS.unlink(SAVE_FILE_PATH)
      } catch (error) {
        /* empty */
      }
    }
  }

  toOffice(fileBuffer: ArrayBuffer, format: IDocumentOfficeFormat): Promise<ArrayBuffer> {
    module.FS.writeFile(CREATE_FILE_PATH, new Uint8Array(fileBuffer))

    const OUTPUT_FILE_PATH = `/save.${format}`

    const output = {
      file: OUTPUT_FILE_PATH,
      format,
    }

    try {
      execJsonCommand('gdpicture/process', {
        input: {
          file: CREATE_FILE_PATH,
        },
        output,
      })

      return module.FS.readFile(OUTPUT_FILE_PATH).buffer
    } finally {
      try {
        module.FS.unlink(OUTPUT_FILE_PATH)
      } catch (error) {
        // eslint-disable-next-line no-console
        console.log(error.message)
      }
    }
  }

  async populateDocumentTemplate(
    document: ArrayBuffer,
    data: TemplateDataToPopulateDocument,
  ): Promise<ArrayBuffer> {
    module.FS.writeFile(CREATE_DOCX_PATH, new Uint8Array(document))

    let jsonString

    try {
      jsonString = JSON.stringify(data, null, 2)
    } catch (error) {
      throw new Error('Invalid config data')
    }

    // Write the JSON string to a file
    module.FS.writeFile(TEMPLATE_DATA_JSON_PATH, jsonString)

    try {
      execJsonCommand('gdpicture/process-office-template', {
        inputFile: CREATE_DOCX_PATH,
        modelAndConfigFile: TEMPLATE_DATA_JSON_PATH,
        outputFile: SAVE_DOCX_PATH,
      })

      return module.FS.readFile(SAVE_DOCX_PATH).buffer
    } finally {
      try {
        module.FS.unlink(SAVE_DOCX_PATH)
        module.FS.unlink(TEMPLATE_DATA_JSON_PATH)
      } catch (error) {
        // eslint-disable-next-line no-console
        console.log(error.message)
      }
    }
  }
}
