import { PSPDFKitError, invariant } from '@pspdfkit/shared'

import type { FontSubstitution } from '@/models/FontSubstitution'
import type { IConformance } from '@/enums/PDFAConformance'
import type {
  GdPictureCommands,
  Conformance as GdPictureConformance,
  GdPictureInterface,
  GdPictureSpawner,
  Request,
} from './GdPictureTypes'
import type {
  FetchedCustomFont,
  FetchedNodeCustomFont,
  MessageId,
  PromisePair,
} from '@pspdfkit/core'
import type { TemplateDataToPopulateDocument } from '@/models/TemplateDataToPopulateDocument'
import type { IDocumentOfficeFormat } from '@/enums/OfficeDocumentFormat'

/**
 * This client is responsible for opening a web worker and pass results of the API back and forth.
 */

class GdPictureClient implements GdPictureInterface {
  private workerSpawner: GdPictureSpawner | null
  private requests = new Map<MessageId, PromisePair>()
  private nextRequestId: MessageId = 1
  private readonly moduleLoadPromise: ReturnType<GdPictureCommands['loadModule']> | null

  constructor({
    baseUrl,
    aot,
    mainThreadOrigin,
    licenseKey,
    customFonts,
    dynamicFonts,
    fontSubstitutions,
    workerSpawner,
    wasmLoaderPath,
  }: {
    baseUrl: string
    aot: boolean
    mainThreadOrigin: string
    licenseKey: string | undefined | null
    customFonts?: FetchedCustomFont[] | FetchedNodeCustomFont[] | undefined | null
    dynamicFonts?: string | null
    fontSubstitutions?: FontSubstitution[] | null
    workerSpawner: GdPictureSpawner
    wasmLoaderPath?: string
  }) {
    this.workerSpawner = workerSpawner
    this.workerSpawner.setMessageHandler(this.handleMessage)
    this.moduleLoadPromise = this.sendRequest('loadModule', [
      // @ts-expect-error
      wasmLoaderPath ? { baseUrl, wasmLoaderPath } : baseUrl,
      aot,
      mainThreadOrigin,
      licenseKey,
      customFonts,
      dynamicFonts,
      fontSubstitutions,
    ])
  }

  toOffice(document: ArrayBuffer, format: IDocumentOfficeFormat): Promise<ArrayBuffer> {
    return this.sendRequest('toOffice', [document, format])
  }

  toPdf(document: ArrayBuffer, conformance?: IConformance): Promise<ArrayBuffer> {
    let gdpConformance: GdPictureConformance | undefined

    if (conformance) {
      gdpConformance = conformance
        .replace('pdf', 'pdf_')
        .replaceAll('-', '_') as unknown as GdPictureConformance
    }

    return this.sendRequest('toPdf', [document, gdpConformance])
  }

  async populateDocumentTemplate(
    document: ArrayBuffer,
    data: TemplateDataToPopulateDocument,
  ): ReturnType<GdPictureCommands['populateDocumentTemplate']> {
    return this.sendRequest('populateDocumentTemplate', [document, data])
  }

  destroy() {
    this.workerSpawner?.terminate()
    this.workerSpawner = null
  }

  /**
   * When we receive messages from the worker, we look up the request ID in our requests map and
   * resolve the promises accordingly.
   *
   * If the id is `0`, we now that we've successfully initialized
   */
  private handleMessage = (event: MessageEvent) => {
    const response = event.data

    const request = this.requests.get(response.id)

    invariant(request, `No request was made for id ${response.id}.`)

    const { resolve, reject } = request

    this.requests.delete(response.id)

    if (response.error) {
      const err = new PSPDFKitError(response.error)

      err.callArgs = response.callArgs
      reject(err)
    } else {
      resolve(response.result)
    }
  }

  private async sendRequest<K extends keyof GdPictureCommands>(
    action: K,
    args: Parameters<GdPictureCommands[K]>,
  ): Promise<Awaited<ReturnType<GdPictureCommands[K]>>> {
    invariant(this.workerSpawner, 'GdPictureClient has been destroyed')

    if (this.moduleLoadPromise) {
      await this.moduleLoadPromise
    }

    const worker = this.workerSpawner

    return new Promise<Awaited<ReturnType<GdPictureCommands[K]>>>((resolve, reject) => {
      const id = this.assignId()

      const request: Request<K> = {
        id,
        action,
        args,
      }
      // When the arg list contains a transferable object, we pass it's ownership as well
      const transferList = [...args].filter(
        a => a instanceof ArrayBuffer,
      ) as unknown as ArrayBuffer[]

      worker.postMessage(request, transferList)

      this.requests = this.requests.set(id, {
        resolve: resolve as () => void,
        reject,
      })
    })
  }

  /**
   * Returns a new, unique identifier.
   */
  private assignId(): MessageId {
    const id = this.nextRequestId

    this.nextRequestId = this.nextRequestId + 1

    return id
  }
}

export default GdPictureClient
